struct Stock {
    let symbol: String
    let price: Double
}

class APIClient {
    let baseURL = "https://api.yourfinancialservice.com"
    let apiKey = "your_api_key"

    func executeTrade(stock: Stock, quantity: Int, completion: @escaping (Bool, Error?) -> Void) {
        guard let url = URL(string: "\(baseURL)/trade") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue(apiKey, forHTTPHeaderField: "Authorization")
        
        let tradeRequest = ["symbol": stock.symbol, "quantity": quantity]
        request.httpBody = try? JSONSerialization.data(withJSONObject: tradeRequest, options: [])
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(false, error)
                return
            }
            completion(true, nil)
        }
        task.resume()
    }
}

class PortfolioManager {
    var portfolio: [String: Int] = [:] // Dictionary to store stock symbol and their holdings
    
    func addStock(symbol: String, quantity: Int) {
        portfolio[symbol, default: 0] += quantity
    }
    
    func removeStock(symbol: String, quantity: Int) {
        if let currentQuantity = portfolio[symbol] {
            if currentQuantity <= quantity {
                portfolio.removeValue(forKey: symbol)
            } else {
                portfolio[symbol] = currentQuantity - quantity
            }
        }
    }
    
    func getTotalValue(stockPrices: [String: Double]) -> Double {
        var totalValue: Double = 0.0
        for (symbol, quantity) in portfolio {
            totalValue += (stockPrices[symbol] ?? 0) * Double(quantity)
        }
        return totalValue
    }
}